#include<bits/stdc++.h>using namespace std;int main(){    ios::sync_with_stdio(false);    cin.tie(0);    cout.tie(0);    int t;    cin>>t;    while(t--){		string a,b;		cin>>a>>b;		if((a.size()*2-1)<b.size()){			cout<<"NO"<<'\n';			continue;		}		bool f=true;		for(int i=0;i<a.size();i++){			for(int j=0;j+i<=a.size();j++){				string c=a.substr(i,j);				int num=b.size()-c.size();				int k=i+j-1;				while(num>0&&k-1>=0){					k--;					c+=a[k];					num--;				}				if(c==b){					f=false;					cout<<"YES"<<'\n';					break;				}				//cout<<c<<" ";			}			if(!f){				break;			}		}		if(f){			cout<<"NO"<<'\n';		}	}    return 0;}